module.render:
    const percent = args.percent || '0';
    const label = args.label || '';
    const color = args.color || 'var(--accent-color)';
    const track = (args.track && String(args.track).trim()) || '#eee';
    const labelcolor = (args.labelcolor && String(args.labelcolor).trim()) || '#555';
    let hN = parseInt(args.height, 10); const height = (hN >= 2 && hN <= 48) ? hN : 12;
    const showValue = String(args.showvalue) !== 'false';
    let html = `\n\n<div class="mdp-mod-progress" style="--prog-color: ${color}; --prog-track: ${track}; --prog-label: ${labelcolor}; --prog-h: ${height}px;">
<div class="mdp-progress-info">`;
    if (label) {
      html += `<span class="mdp-progress-label">${label}</span>`;
    }
    if (showValue) {
      html += `<span class="mdp-progress-percent">${percent}%</span>`;
    }
    html += `
</div>
<div class="mdp-progress-bar-bg">
<div class="mdp-progress-bar-fill" style="width: ${percent}%;"></div>
</div>
</div>\n\n`;
    return html;
